import{_ as t,o as e,c as p,e as o}from"./app-DHLwyd6l.js";const c={},s=o("<p>рҹҳ„ рҹҳҶ рҹҳҠ рҹҳғ рҹҳҸ рҹҳҚ рҹҳҳ рҹҳҡ рҹҳі рҹҳҢ рҹҳҶ рҹҳҒ рҹҳү рҹҳң рҹҳқ рҹҳҖ рҹҳ— рҹҳҷ рҹҳӣ рҹҳҙ рҹҳҹ рҹҳҰ рҹҳ§ рҹҳ® рҹҳ¬ рҹҳ• рҹҳҜ рҹҳ‘ рҹҳ’ рҹҳ… рҹҳ“ рҹҳҘ рҹҳ© рҹҳ” рҹҳһ рҹҳ– рҹҳЁ рҹҳ° рҹҳЈ рҹҳў рҹҳӯ рҹҳӮ рҹҳІ рҹҳұ рҹҳ« рҹҳ  рҹҳЎ рҹҳӨ рҹҳӘ рҹҳӢ рҹҳ· рҹҳҺ рҹҳө рҹ‘ҝ рҹҳҲ рҹҳҗ рҹҳ¶ рҹҳҮ рҹ‘Ҫ рҹ’ӣ</p><p>рҹ’ҷ рҹ’ң вқӨпёҸ рҹ’ҡ рҹ’” рҹ’“ рҹ’— рҹ’• рҹ’һ рҹ’ҳ рҹ’– вңЁ вӯҗ рҹҢҹ рҹ’« рҹ’Ҙ рҹ’Ҙ рҹ’ў вқ— вқ“ вқ• вқ” рҹ’Ө рҹ’Ё рҹ’Ұ рҹҺ¶ рҹҺө рҹ”Ҙ рҹ’© рҹ’© рҹ’© рҹ‘Қ рҹ‘Қ рҹ‘Һ рҹ‘Һ рҹ‘Ң рҹ‘Ҡ рҹ‘Ҡ вңҠ вңҢпёҸ рҹ‘Ӣ вңӢ вңӢ рҹ‘җ вҳқпёҸ рҹ‘Ү рҹ‘Ҳ рҹ‘ү рҹҷҢ рҹҷҸ рҹ‘Ҷ рҹ‘Ҹ рҹ’Ә рҹӨҳ рҹ–• рҹҸғ рҹҸғ рҹ‘« рҹ‘Ә рҹ‘¬ рҹ‘ӯ рҹ’ғ рҹ‘Ҝ рҹҷҶ рҹҷ… рҹ’Ғ</p><p>рҹҷӢ рҹ‘° рҹҷҺ рҹҷҚ рҹҷҮ рҹ’‘ рҹ’Ҷ рҹ’Ү рҹ’… рҹ‘Ұ рҹ‘§ рҹ‘© рҹ‘Ё рҹ‘¶ рҹ‘ө рҹ‘ҙ рҹ‘ұ рҹ‘І рҹ‘і рҹ‘· рҹ‘® рҹ‘ј рҹ‘ё рҹҳә рҹҳё рҹҳ» рҹҳҪ рҹҳј рҹҷҖ рҹҳҝ рҹҳ№ рҹҳҫ рҹ‘№ рҹ‘ә рҹҷҲ рҹҷү рҹҷҠ рҹ’Ӯ рҹ’Җ рҹҗҫ рҹ‘„ рҹ’Ӣ рҹ’§ рҹ‘Ӯ рҹ‘Җ рҹ‘ғ рҹ‘… рҹ’Ң рҹ‘Ө рҹ‘Ҙ рҹ’¬ рҹ’ӯ вҳҖпёҸ вҳ” вҳҒпёҸ вқ„пёҸ вӣ„ вҡЎ рҹҢҖ рҹҢҒ рҹҢҠ рҹҗұ</p><p>рҹҗ¶ рҹҗӯ рҹҗ№ рҹҗ° рҹҗә рҹҗё рҹҗҜ рҹҗЁ рҹҗ» рҹҗ· рҹҗҪ рҹҗ® рҹҗ— рҹҗө рҹҗ’ рҹҗҙ рҹҗҺ рҹҗ« рҹҗ‘ рҹҗҳ рҹҗј рҹҗҚ рҹҗҰ рҹҗӨ рҹҗҘ рҹҗЈ рҹҗ” рҹҗ§ рҹҗў рҹҗӣ рҹҗқ рҹҗң рҹҗһ рҹҗҢ рҹҗҷ рҹҗ  рҹҗҹ рҹҗі рҹҗӢ рҹҗ¬ рҹҗ„ рҹҗҸ рҹҗҖ рҹҗғ рҹҗ… рҹҗҮ рҹҗү рҹҗҗ рҹҗ“ рҹҗ• рҹҗ– рҹҗҒ рҹҗӮ рҹҗІ рҹҗЎ рҹҗҠ рҹҗӘ рҹҗҶ рҹҗҲ рҹҗ©</p><p>рҹҗҫ рҹ’җ рҹҢё рҹҢ· рҹҚҖ рҹҢ№ рҹҢ» рҹҢә рҹҚҒ рҹҚғ рҹҚӮ рҹҢҝ рҹҚ„ рҹҢө рҹҢҙ рҹҢІ рҹҢі рҹҢ° рҹҢұ рҹҢј рҹҢҫ рҹҗҡ рҹҢҗ рҹҢһ рҹҢқ рҹҢҡ рҹҢ‘ рҹҢ’ рҹҢ“ рҹҢ” рҹҢ• рҹҢ– рҹҢ— рҹҢҳ рҹҢң рҹҢӣ рҹҢҷ рҹҢҚ рҹҢҺ рҹҢҸ рҹҢӢ рҹҢҢ вӣ… рҹҺҚ рҹ’қ рҹҺҺ рҹҺ’ рҹҺ“ рҹҺҸ рҹҺҶ рҹҺҮ рҹҺҗ рҹҺ‘ рҹҺғ рҹ‘» рҹҺ… рҹҺ„ рҹҺҒ рҹ”” рҹ”• рҹҺӢ рҹҺү рҹҺҠ</p><p>рҹҺҲ рҹ”® рҹ’ҝ рҹ“Җ рҹ’ҫ рҹ“· рҹ“№ рҹҺҘ рҹ’» рҹ“ә рҹ“ұ вҳҺпёҸ вҳҺпёҸ рҹ“һ рҹ“ҹ рҹ“  рҹ’Ҫ рҹ“ј рҹ”ү рҹ”Ҳ рҹ”Ү рҹ“ў рҹ“Ј вҢӣ вҸі вҸ° вҢҡ рҹ“» рҹ“Ў вһҝ рҹ”Қ рҹ”Һ рҹ”“ рҹ”’ рҹ”Ҹ рҹ”җ рҹ”‘ рҹ’Ў рҹ”Ұ рҹ”Ҷ рҹ”… рҹ”Ң рҹ”Ӣ рҹ“І вңүпёҸ рҹ“« рҹ“® рҹӣҖ рҹӣҒ рҹҡҝ рҹҡҪ рҹ”§ рҹ”© рҹ”Ё рҹ’ә рҹ’° рҹ’ҙ рҹ’ө рҹ’· рҹ’¶ рҹ’і рҹ’ё рҹ“§ рҹ“Ҙ</p><p>рҹ“Ө вңүпёҸ рҹ“Ё рҹ“Ҝ рҹ“Ә рҹ“¬ рҹ“ӯ рҹ“Ұ рҹҡӘ рҹҡ¬ рҹ’Ј рҹ”« рҹ”Ә рҹ’Ҡ рҹ’ү рҹ“„ рҹ“ғ рҹ“‘ рҹ“Ҡ рҹ“Ҳ рҹ“ү рҹ“ң рҹ“Ӣ рҹ“Ҷ рҹ“… рҹ“Ү рҹ“Ғ рҹ“Ӯ вңӮпёҸ рҹ“Ң рҹ“Һ вң’пёҸ вңҸпёҸ рҹ“Ҹ рҹ“җ рҹ“• рҹ“— рҹ“ҳ рҹ“ҷ рҹ““ рҹ“” рҹ“’ рҹ“ҡ рҹ”– рҹ“ӣ рҹ”¬ рҹ”ӯ рҹ“° рҹҸҲ рҹҸҖ вҡҪ вҡҫ рҹҺҫ рҹҺұ рҹҸү рҹҺі вӣі рҹҡө рҹҡҙ рҹҸҮ рҹҸӮ рҹҸҠ рҹҸ„</p><p>рҹҺҝ рҹ‘ҫ вҷ пёҸ вҷҘпёҸ вҷЈпёҸ вҷҰпёҸ рҹ’Һ рҹ’Қ рҹҸҶ рҹҺј рҹҺ№ рҹҺ» рҹҺ® рҹғҸ рҹҺҙ рҹҺІ рҹҺҜ рҹҖ„ рҹҺ¬ рҹ“қ рҹ“қ рҹ“– рҹҺЁ рҹҺӨ рҹҺ§ рҹҺә рҹҺ· рҹҺё рҹ‘һ рҹ‘Ў рҹ‘  рҹ’„ рҹ‘ў рҹ‘• рҹ‘• рҹ‘” рҹ‘ҡ рҹ‘— рҹҺҪ рҹ‘– рҹ‘ҳ рҹ‘ҷ рҹҺҖ рҹҺ© рҹ‘‘ рҹ‘’ рҹ‘һ рҹҢӮ рҹ’ј рҹ‘ң рҹ‘қ рҹ‘ӣ рҹ‘“ рҹҺЈ вҳ• рҹҚө рҹҚ¶ рҹҚј рҹҚә рҹҚ» рҹҚё рҹҚ№ рҹҚ· рҹҚҙ рҹҚ• рҹҚ”</p><p>рҹҚҹ рҹҚ— рҹҚ– рҹҚқ рҹҚӣ рҹҚӨ рҹҚұ рҹҚЈ рҹҚҘ рҹҚҷ рҹҚҳ рҹҚҡ рҹҚң рҹҚІ рҹҚў рҹҚЎ рҹҘҡ рҹҚһ рҹҚ© рҹҚ® рҹҚҰ рҹҚЁ рҹҚ§ рҹҺӮ рҹҚ° рҹҚӘ рҹҚ« рҹҚ¬ рҹҚӯ рҹҚҜ рҹҚҺ рҹҚҸ рҹҚҠ рҹҚӢ рҹҚ’ рҹҚҮ рҹҚү рҹҚ“ рҹҚ‘ рҹҚҲ рҹҚҢ рҹҚҗ рҹҚҚ рҹҚ  рҹҚҶ рҹҚ… рҹҢҪ рҹҸ  рҹҸЎ рҹҸ« рҹҸў рҹҸЈ рҹҸҘ рҹҸҰ рҹҸӘ рҹҸ© рҹҸЁ рҹ’’ вӣӘ рҹҸ¬ рҹҸӨ рҹҢҮ</p><p>рҹҢҶ рҹҸҜ рҹҸ° вӣә рҹҸӯ рҹ—ј рҹ—ҫ рҹ—» рҹҢ„ рҹҢ… рҹҢ  рҹ—Ҫ рҹҢү рҹҺ  рҹҢҲ рҹҺЎ вӣІ рҹҺў рҹҡў рҹҡӨ вӣө вӣө рҹҡЈ вҡ“ рҹҡҖ вңҲпёҸ рҹҡҒ рҹҡӮ рҹҡҠ рҹҡһ рҹҡІ рҹҡЎ рҹҡҹ рҹҡ  рҹҡң рҹҡҷ рҹҡҳ рҹҡ— рҹҡ— рҹҡ• рҹҡ– рҹҡӣ рҹҡҢ рҹҡҚ рҹҡЁ рҹҡ“ рҹҡ” рҹҡ’ рҹҡ‘ рҹҡҗ рҹҡҡ рҹҡӢ рҹҡү рҹҡҶ рҹҡ… рҹҡ„ рҹҡҲ рҹҡқ рҹҡғ рҹҡҺ</p><p>рҹҺ« вӣҪ рҹҡҰ рҹҡҘ вҡ пёҸ рҹҡ§ рҹ”° рҹҸ§ рҹҺ° рҹҡҸ рҹ’Ҳ вҷЁпёҸ рҹҸҒ рҹҺҢ рҹҸ® рҹ—ҝ рҹҺӘ рҹҺӯ рҹ“Қ рҹҡ© рҹҮҜрҹҮө рҹҮ°рҹҮ· рҹҮЁрҹҮі рҹҮәрҹҮё рҹҮ«рҹҮ· рҹҮӘрҹҮё рҹҮ®рҹҮ№ рҹҮ·рҹҮә рҹҮ¬рҹҮ§ рҹҮ¬рҹҮ§ рҹҮ©рҹҮӘ 1пёҸвғЈ 2пёҸвғЈ 3пёҸвғЈ 4пёҸвғЈ 5пёҸвғЈ 6пёҸвғЈ 7пёҸвғЈ 8пёҸвғЈ 9пёҸвғЈ рҹ”ҹ рҹ”ў 0пёҸвғЈ #пёҸвғЈ рҹ”Ј в—ҖпёҸ в¬ҮпёҸ в–¶пёҸ в¬…пёҸ рҹ”  рҹ”Ў рҹ”Ө вҶҷпёҸ вҶҳпёҸ вһЎпёҸ в¬ҶпёҸ вҶ–пёҸ вҶ—пёҸ вҸ¬ вҸ« рҹ”Ҫ вӨөпёҸ вӨҙпёҸ вҶ©пёҸ вҶӘпёҸ вҶ”пёҸ вҶ•пёҸ</p><p>рҹ”ј рҹ”ғ рҹ”„ вҸӘ вҸ© в„№пёҸ рҹҶ— рҹ”Җ рҹ”Ғ рҹ”Ӯ рҹҶ• рҹ”қ рҹҶҷ рҹҶ’ рҹҶ“ рҹҶ– рҹҺҰ рҹҲҒ рҹ“¶ рҹҲө рҹҲӮпёҸ рҹҡ» рҹҡ№ рҹҡә рҹҡј рҹҡӯ рҹ…ҝпёҸ вҷҝ рҹҡҮ рҹӣ„ рҹү‘ рҹҡҫ рҹҡ° рҹҡ® гҠҷпёҸ гҠ—пёҸ в“ӮпёҸ рҹӣӮ рҹӣ… рҹӣғ рҹүҗ рҹҶ‘ рҹҶҳ рҹҶ” рҹҡ« рҹ”һ рҹ“ө рҹҡҜ рҹҡ· рҹҡұ рҹҡі рҹҡё вӣ” вңіпёҸ вқҮпёҸ вңҙпёҸ рҹ’ҹ рҹҶҡ рҹ“і рҹ“ҙ</p><p>рҹ’№ рҹ’ұ вҷҲ вҷү вҷҠ вҷӢ вҷҢ вҷҚ вҷҺ вҷҸ вҷҗ вҷ‘ вҷ’ вҷ“ вӣҺ рҹ”Ҝ вқҺ рҹ…°пёҸ рҹ…ұпёҸ рҹҶҺ рҹ…ҫпёҸ рҹ’  вҷ»пёҸ рҹ”ҡ рҹ”ҷ рҹ”ӣ рҹ”ң рҹ•җ рҹ•ң рҹ•ҷ рҹ•Ҙ рҹ•ҡ рҹ•Ұ рҹ•ӣ рҹ•§ рҹ•‘ рҹ•қ рҹ•’ рҹ•һ рҹ•“ рҹ•ҹ рҹ•” рҹ•  рҹ•• рҹ•Ў рҹ•– рҹ•ў рҹ•— рҹ•Ј рҹ•ҳ рҹ•Ө рҹ’І В©пёҸ В®пёҸ в„ўпёҸ вқҢ вқ— вҖјпёҸ вҒүпёҸ вӯ• вң–пёҸ вһ• вһ– вһ— рҹ’® рҹ’Ҝ вң”пёҸ вҳ‘пёҸ рҹ”ҳ рҹ”— вһ° гҖ°пёҸ гҖҪпёҸ рҹ”ұ в–Ә в–«пёҸ в—ҫ в—Ҫ в—јпёҸ в—»пёҸ в¬ӣ в¬ң вң… рҹ”І рҹ”і вҡ« вҡӘ рҹ”ҙ рҹ”ө рҹ”· рҹ”¶ рҹ”№ рҹ”ё рҹ”ә рҹ”»</p>",13),a=[s];function n(r,_){return e(),p("div",null,a)}const l=t(c,[["render",n],["__file","еӣҫж Ү.html.vue"]]),d=JSON.parse('{"path":"/tools/docs/interview/%E7%BC%96%E5%86%99%E6%96%87%E6%A1%A3%E5%8A%A9%E6%89%8B/%E5%9B%BE%E6%A0%87.html","title":"","lang":"zh-CN","frontmatter":{},"headers":[],"git":{},"filePathRelative":"tools/docs/interview/зј–еҶҷж–ҮжЎЈеҠ©жүӢ/еӣҫж Ү.md"}');export{l as comp,d as data};
